package main

import (
	"errors"
	"sync"
)

type Bank struct {
	mu       sync.RWMutex
	accounts map[string]float64
}

func NewBank() *Bank {
	return &Bank{
		accounts: make(map[string]float64),
	}
}

func (b *Bank) CreateAccount(accountID string, initialBalance float64) error {
	b.mu.Lock()
	defer b.mu.Unlock()

	if _, exists := b.accounts[accountID]; exists {
		return errors.New("account already exists")
	}

	b.accounts[accountID] = initialBalance
	return nil
}

func (b *Bank) GetBalance(accountID string) (float64, error) {
	b.mu.RLock()
	defer b.mu.RUnlock()

	balance, exists := b.accounts[accountID]
	if !exists {
		return 0, errors.New("account not found")
	}

	return balance, nil
}

func (b *Bank) Deposit(accountID string, amount float64) error {
	if amount <= 0 {
		return errors.New("deposit amount must be positive")
	}

	b.mu.Lock()
	defer b.mu.Unlock()

	if _, exists := b.accounts[accountID]; !exists {
		return errors.New("account not found")
	}

	b.accounts[accountID] += amount
	return nil
}

func (b *Bank) Withdraw(accountID string, amount float64) error {
	if amount <= 0 {
		return errors.New("withdrawal amount must be positive")
	}

	b.mu.Lock()
	defer b.mu.Unlock()

	balance, exists := b.accounts[accountID]
	if !exists {
		return errors.New("account not found")
	}

	if balance < amount {
		return errors.New("insufficient funds")
	}

	b.accounts[accountID] -= amount
	return nil
}

func (b *Bank) Transfer(fromAccountID, toAccountID string, amount float64) error {
	if amount <= 0 {
		return errors.New("transfer amount must be positive")
	}

	b.mu.Lock()
	defer b.mu.Unlock()

	fromBalance, fromExists := b.accounts[fromAccountID]
	if !fromExists {
		return errors.New("source account not found")
	}

	if _, toExists := b.accounts[toAccountID]; !toExists {
		return errors.New("destination account not found")
	}

	if fromBalance < amount {
		return errors.New("insufficient funds")
	}

	b.accounts[fromAccountID] -= amount
	b.accounts[toAccountID] += amount
	return nil
}

func (b *Bank) GetAllBalances() map[string]float64 {
	b.mu.RLock()
	defer b.mu.RUnlock()

	balances := make(map[string]float64, len(b.accounts))
	for accountID, balance := range b.accounts {
		balances[accountID] = balance
	}

	return balances
}